func hashFlowID(fsName, fDistinguisher string) uint64 {
        hash := sha256.New()
        var sep = [1]byte{0}
        hash.Write([]byte(fsName))
        hash.Write(sep[:])
        hash.Write([]byte(fDistinguisher))
        var sum [32]byte
        hash.Sum(sum[:0])
        return binary.LittleEndian.Uint64(sum[:8])
}

